    case P3D_MULTI_CONTROLLER:
        dch = new tlMultiControllerChunk16(&ch);
        break;
    case P3D_FRAME_CONTROLLER:
        dch = new tlFrameControllerChunk16(&ch);
        break;
    case P3D_SKELETON:
        dch = new tlSkeletonChunk16(&ch);
        break;
