        break;
    case Pure3D::BillboardObject::QUAD_GROUP:
        dch = new tlBillboardQuadGroupChunk(&ch);
        break;
    case SRR2::ChunkID::LENS_FLARE_DSG:
        dch = new tlLensFlareDSGChunk(&ch);
        break;
